SELECT properties.property_id, properties.title, properties.cost_per_night, owners.owner_name, owners.contact_email
FROM properties
JOIN owners ON properties.owner_id = owners.owner_id;

SELECT COUNT(*) 
FROM bookings 
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Jane Doe');

SELECT AVG(num_amenities) AS avg_amenities_per_property
FROM (
    SELECT COUNT(amenity_id) AS num_amenities
    FROM amenities
    GROUP BY property_id
);

SELECT users.user_name, messages.message
FROM messages
LEFT JOIN users ON messages.user_id = users.user_id;

SELECT owners.owner_name, owners.contact_email
FROM owners
JOIN properties ON owners.owner_id = properties.owner_id
WHERE properties.property_id IN (
    SELECT property_id FROM bookings
);
